+        assert!(buffer_contains(&buf, area, "press g to toggle"));
+    }
+
+    // ── Render: Genealogy view ──────────────────────────────────────
+
+    #[test]
+    fn detail_genealogy_view() {
+        let area = Rect::new(0, 0, 60, 16);
+        let mut buf = Buffer::empty(area);
